// n8n Code node (JavaScript)
// Purpose: Convert HeyReach conversation messages[] into a single conversation text variable
// Works even when there are multiple messages.

function safeGet(obj, path, fallback = null) {
  return path.split('.').reduce((acc, key) => {
    if (acc && Object.prototype.hasOwnProperty.call(acc, key)) return acc[key];
    return undefined;
  }, obj) ?? fallback;
}

const input = $input.all();

// Your data structure: input[0].json.items[0] contains the conversation object
const wrapper = input[0]?.json;
const convoItem = wrapper?.items?.[0];

if (!convoItem) {
  return [{
    json: {
      conversation_text: "",
      error: "No conversation item found at json.items[0]"
    }
  }];
}

// Extract lead info
const profile = convoItem.correspondentProfile || {};
const leadName = [profile.firstName, profile.lastName].filter(Boolean).join(" ").trim();
const leadProfileUrl = profile.profileUrl || "";
const leadLinkedinId = profile.linkedin_id || "";

// Extract messages
const messages = Array.isArray(convoItem.messages) ? convoItem.messages : [];

// Sort chronologically (oldest -> newest)
messages.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));

// Format conversation into one variable
const formattedLines = messages.map((m) => {
  const sender = m.sender === "ME" ? "ME" : "THEM";
  const time = m.createdAt ? new Date(m.createdAt).toISOString().replace("T", " ").replace("Z", "") : "Unknown time";
  const body = (m.body || "").trim().replace(/\s+/g, " ");
  const extra = [];

  if (m.isInMail) extra.push("InMail");
  if (m.subject) extra.push(`Subject: ${m.subject}`);
  if (m.postLink) extra.push(`Post: ${m.postLink}`);

  const meta = extra.length ? ` [${extra.join(" | ")}]` : "";
  return `${sender} (${time})${meta}: ${body}`;
}).filter(Boolean);

// Build final conversation string
const conversation_text = formattedLines.join("\n");

// Optional: include a header (recommended so AI has context)
const conversation_with_header =
  `Conversation with ${leadName || "Unknown"} (${leadProfileUrl || "No URL"}):\n` +
  `${conversation_text || "(no messages found)"}`;

// Output for downstream AI Agent node
return [{
  json: {
    lead_name: leadName,
    lead_profile_url: leadProfileUrl,
    lead_linkedin_id: leadLinkedinId,
    conversation_text: conversation_with_header,

    // Optional debug
    total_messages: messages.length,
    last_message_at: convoItem.lastMessageAt || null,
    last_message_text: convoItem.lastMessageText || null
  }
}];

const profileUrl = $json.profileUrl || ""; // adjust field name as needed

// Extract LinkedIn ID from URL
let linkedinId = "";

if (profileUrl) {
  // Remove trailing slash if present
  const cleanUrl = profileUrl.replace(/\/$/, "");

  // Extract the part after /in/
  const match = cleanUrl.match(/linkedin\.com\/in\/([^\/\?]+)/);

  if (match && match[1]) {
    linkedinId = match[1];
  }
}

return [
  {
    json: {
      ...$input.item.json,
      linkedinId: linkedinId
    }
  }
];
